                                        ></el-option>
                                        <el-option
                                            label="Crédito"
                                            value="02"
                                        ></el-option>
                                        <el-option
                                            label="Contado"
                                            value="01"
                                        ></el-option>
                                    </el-select>
                                    <small
                                        class="form-control-feedback"
                                        v-if="errors.payment_condition_id"
                                        v-text="errors.payment_condition_id[0]"
                                    ></small>
                                </div>
