                                        <label class="control-label">T. Detracción<span class="text-danger"> *</span></label>
                                        <el-input v-model="form.detraction.amount" readonly> <i slot="prefix" class="el-icon-edit-outline"></i></el-input>
                                    </div>
                                </div>
                            </div> -->

