                                        <td class="text-end">
                                            {{ currency_type.symbol }}
                                            {{ form.total_prepayment }}
                                        </td>
                                    </tr>
                                    <!-- <tr v-if="form.total_discount > 0">
                                        <td>DESCUENTOS</td>
                                        <td>:</td>
                                        <td class="text-end">{{ currency_type.symbol }} {{ form.total_discount }}</td>
                                    </tr> -->
                                    <tr v-if="form.total_igv > 0">
                                        <td>IGV</td>
                                        <td>:</td>
                                        <td class="text-end">
                                            {{ currency_type.symbol }}
                                            {{ form.total_igv }}
                                        </td>
                                    </tr>
                                </table>

                                <template v-if="form.total > 0">
                                    <span class="text-end" v-if="form.total > 0"
                                        ><b>TOTAL VENTA: </b
                                        >{{ currency_type.symbol }}
                                        {{ form.total }}</span
                                    >
                                </template>
                                <template v-if="form.total > 0">
                                    <span class="text-end" v-if="form.total > 0"
                                        ><b>REDONDEO: </b
                                        >{{ currency_type.symbol }}
                                        {{ form.total_rounded }}</span
                                    >
                                </template>
                                <template v-if="form.total > 0">
                                    <h4 class="text-end" v-if="form.total > 0">
                                        <b>TOTAL A PAGAR: </b
                                        >{{ currency_type.symbol
                                        }}{{ form.total_payment }}
                                    </h4>
                                </template>
                                <template v-if="form.boxes">
                                    <h4
                                        v-for="(data, idx) in form.boxes"
                                        :key="idx"
                                        class="text-end"
                                    >
                                        <b
                                            >TOTAL
                                            {{ data.method.toUpperCase() }}: </b
                                        >{{ currency_type.symbol
                                        }}{{ data.amount }}
                                    </h4>
                                </template>
                            </div>
                        </div>
                    </div>

                    <div class="form-actions text-end pt-2 pb-2">
                        <el-button @click.prevent="close()">Cancelar</el-button>
                        <el-button
                            class="submit"
                            type="primary"
                            native-type="submit"
                            :loading="loading_submit"
                            v-if="form.items.length > 0 && this.dateValid"
                            >Generar
                        </el-button>
                    </div>
                </form>
            </div>

            <document-form-item
                :showDialog.sync="showDialogAddItem"
                :recordItem="recordItem"
                :restringir_stock="restringir_stock"
                :isEditItemNote="false"
                :operation-type-id="form.operation_type_id"
                :currency-type-id-active="form.currency_type_id"
                :exchange-rate-sale="form.exchange_rate_sale"
                :typeUser="typeUser"
                :configuration="configuration"
                :editNameProduct="configuration.edit_name_product"
                :percentage_igv="percentage_igv"
                @add="addRow"
            ></document-form-item>

            <person-form
                :showDialog.sync="showDialogNewPerson"
                type="customers"
                :external="true"
                :user_id="form.user_id"
                :input_person="input_person"
                :document_type_id="form.document_type_id"
            ></person-form>

            <document-options
                :showDialog.sync="showDialogOptions"
                :recordId="documentNewId"
                :editDocument="editDocument"
                :isContingency="is_contingency"
                :showClose="showClose"
            ></document-options>
        </div>
    </div>
</template>

<style>
.input-custom {
    width: 50% !important;
}
.el-textarea__inner {
    height: 65px !important;
    min-height: 65px !important;
}
</style>
<script>
import DocumentFormItem from "./partials/item.vue";
import PersonForm from "../persons/form.vue";
import DocumentOptions from "../documents/partials/options.vue";
import { functions, exchangeRate } from "../../mixins/functions";
import { calculateRowItem } from "../../helpers/functions";
import Logo from "../companies/logo.vue";

export default {
    props: ["id", "typeUser", "configuration", "documentinfo"],
    components: {
        DocumentFormItem,
        PersonForm,
        DocumentOptions,
        Logo
    },
    mixins: [functions, exchangeRate],
    data() {
        return {
            readonly_date_of_due: false,
            sellers: [],
            editandoDocument: false,
            tempMethod: "Efectivo",
            methods: [
                "Efectivo",
                "Yape",
                "PLIN",
                "Culqui",
                "TARJETA: NIUBIZ",
                "TARJETA: IZYPAY",
                "Transferencia"
            ],
            datEmision: {
                disabledDate(time) {
                    return time.getTime() > moment();
                }
            },
            editDocument: false,
            show_restriction: false,
            show_quotations: false,
            dateValid: false,
            restringir_stock: false,
            input_person: {},
            user_default: null,
            showDialogDocumentDetraction: false,
            showDialogQuotations: false,
            has_data_detraction: false,
            showDialogFormHotel: false,
            showDialogFormTransport: false,
            is_client: false,
            recordItem: null,
            resource: "documents",
            showDialogAddItem: false,
            showDialogNewPerson: false,
            showDialogOptions: false,
            loading_submit: false,
            loading_form: false,
            errors: {},
            form: {},
            form2: {},
            form_control: {},
            document_types: [],
            currency_types: [],
            discount_types: [],
            charges_types: [],
            all_customers: [],
            business_turns: [],
            form_payment: {},
            document_types_guide: [],
            customers: [],
            company: null,
            document_type_03_filter: null,
            operation_types: [],
            establishments: [],
            payment_method_types: [],
            establishment: null,
            all_series: [],
            series: [],
            prepayment_documents: [],
            currency_type: {},
            documentNewId: null,
            prepayment_deduction: false,
            activePanel: 0,
            total_global_discount: 0,
            loading_search: false,
            is_amount: true,
            enabled_discount_global: false,
            user: null,
            array_users: [],
            is_receivable: false,
            is_contingency: false,
            cat_payment_method_types: [],
            select_first_document_type_03: false,
            detraction_types: [],
            all_detraction_types: [],
            customer_addresses: [],
            payment_destinations: [],
            validarForm: false,
            payment_conditions: [],
            redondeo: null,
            percentage_igv: null,
            showClose: false,
            loader: false,
            text_loader: "Espere porfavor...."
        };
    },

    async created() {
        await this.initForm();
    

        qz.security.setCertificatePromise((resolve, reject) => {
            this.$http
                .get("/api/qz/crt/override", {
                    responseType: "text"
                })
                .then(response => {
                    resolve(response.data);
                })
                .catch(error => {
                    reject(error.data);
                });
        });
        qz.security.setSignaturePromise(toSign => {
            return (resolve, reject) => {
                this.$http
                    .post("/api/qz/signing", { request: toSign })
                    .then(response => {
                        resolve(response.data);
                    })
                    .catch(error => {
                        reject(error.data);
                    });
            };
        });

        // await this.initForm();

        await this.$http.get(`/documents/tables`).then(response => {
            this.sellers = response.data.sellers;
            this.show_restriction =
                response.data.configuration.show_restriction;
            this.show_quotations = response.data.configuration.show_quotations;
            this.document_types = response.data.document_types_invoice;
            this.document_types_guide = response.data.document_types_guide;
            this.currency_types = response.data.currency_types;
            this.business_turns = response.data.business_turns;
            this.establishments = response.data.establishments;
            this.operation_types = response.data.operation_types;
            this.all_series = response.data.series;
            this.all_customers = response.data.customers;
            this.discount_types = response.data.discount_types;
            this.charges_types = response.data.charges_types;
            this.payment_method_types = response.data.payment_method_types;
            this.enabled_discount_global =
                response.data.enabled_discount_global;
            this.company = response.data.company;
            this.user = response.data.user;
            this.array_users = response.data.users;
            this.document_type_03_filter =
                response.data.document_type_03_filter;
            this.select_first_document_type_03 =
                response.data.select_first_document_type_03;
            this.form.exchange_rate_sale = response.data.exchange_rate_sale;
            this.form.currency_type_id =
                this.currency_types.length > 0
                    ? this.currency_types[0].id
                    : null;
            this.form.establishment_id =
                this.establishments.length > 0
                    ? this.establishments[0].id
                    : null;
            this.form.document_type_id =
                this.document_types.length > 0
                    ? this.document_types[0].id
                    : null;
            this.form.operation_type_id =
                this.operation_types.length > 0
                    ? this.operation_types[0].id
                    : null;
            // this.prepayment_documents = response.datta.prepayment_documents;
            this.is_client = response.data.is_client;
            this.payment_conditions = response.data.payment_conditions;
            // this.cat_payment_method_types = response.data.cat_payment_method_types;
            // this.all_detraction_types = response.data.detraction_types;
            this.payment_destinations = response.data.payment_destinations;
            this.user_default = response.data.user_select.id;
            this.form.user_id = response.data.user_select.id;

            this.selectDocumentType();
            this.changeEstablishment();
            this.changeDateOfIssue();
            this.filterCustomers();
            this.changeDocumentType();
            this.changeCurrencyType();
            this.initInputPerson();

            this.isUpdate();

            this.reloadDataCustomers(this.form.customer_id);
            this.changePaymentCondition();
        });
        //await this.getPercentageIgv();
        this.loading_form = true;
        this.$eventHub.$on("reloadDataPersons", customer_id => {
            this.reloadDataCustomers(customer_id);
        });
        this.$eventHub.$on("initInputPerson", () => {
            this.initInputPerson();
        });
        this.loader = false;
        if (this.show_restriction == 1) {
            this.form_control = {
                id: null,
                stock_control: false
            };
            await this.$http
                .get(`/inventories/configuration/record`)
                .then(response => {
                    if (response.data !== "")
                        this.form_control = response.data.data;
                    this.restringir_stock = response.data.data.stock_control;
                });
        }
        let form_data = {
            establishment_id: this.form.establishment_id,
            date: moment().format("YYYY-MM-DD")
        };
        const response = await this.$http.post("/get_igv", form_data);
        this.percentage_igv = response.data;

            const itemsFromNotes = localStorage.getItem("itemsForNotes");
        if (itemsFromNotes) {
            const itemsParsed = JSON.parse(itemsFromNotes);
            const items = itemsParsed.map(i => i.id);
            const params = {
                items_id: items
            };
            localStorage.removeItem("itemsForNotes");
            const response = await this.$http.get("/documents/search-items", {
                params
            });

            const itemsResponse = response.data.map(i => {
                return this.setItemFromResponse(i, itemsParsed);
            });
       

            this.form.items = itemsResponse.map(i => {
                return calculateRowItem(
                    i,
                    this.form.currency_type_id,
                    this.form.exchange_rate_sale,
                    this.percentage_igv || 0.18
                );
            });
        }

        //parse items from multiple sale notes not group
        // this.processItemsForNotesNotGroup();

        const clientfromDispatchesOrNotes = localStorage.getItem("client");
        if (clientfromDispatchesOrNotes) {
            const client = JSON.parse(clientfromDispatchesOrNotes);
            if (client.identity_document_type_id == 1) {
                this.form.document_type_id = "03";
            } else if (client.identity_document_type_id == 6) {
                this.form.document_type_id = "01";
            }

            await this.searchRemoteCustomers(client.number);
            this.form.customer_id = client.id;
        
            this.changeEstablishment();
            this.filterSeries();
            // this.filterCustomers();
            this.changeCurrencyType();
            localStorage.removeItem("client");
            
        }

        const notesNumbersFromNotes = localStorage.getItem("notes");
        if (notesNumbersFromNotes) {
            this.form.sale_notes_relateds = JSON.parse(notesNumbersFromNotes);
            localStorage.removeItem("notes");
        }
    },

    methods: {
        setItemFromResponse(item, itemsParsed) {
            /* Obtiene el igv del item, si no existe, coloca el gravado*/
            if (item.sale_affectation_igv_type !== undefined) {
                item.affectation_igv_type = item.sale_affectation_igv_type;
            } else {
                item.affectation_igv_type = {
                    active: 1,
                    description: "Gravado - Operación Onerosa",
                    exportation: 0,
                    free: 0,
                    id: "10"
                };
            }
            item.presentation = {};
            item.unit_price = item.sale_unit_price;
            item.item = {
                amount_plastic_bag_taxes: item.amount_plastic_bag_taxes,
                attributes: item.attributes,
                brand: item.brand,
                calculate_quantity: item.calculate_quantity,
                category: item.category,
                currency_type_id: item.currency_type_id,
                currency_type_symbol: item.currency_type_symbol,
                description: item.description,
                full_description: item.full_description,
                has_igv: item.has_igv,
                has_plastic_bag_taxes: item.has_plastic_bag_taxes,
                id: item.id,
                internal_id: item.internal_id,
                item_unit_types: item.item_unit_types,
                lots: item.lots,
                lots_enabled: item.lots_enabled,
                lots_group: item.lots_group,
                model: item.model,
                presentation: {},
                purchase_affectation_igv_type_id:
                    item.purchase_affectation_igv_type_id,
                purchase_unit_price: item.purchase_unit_price,
                sale_affectation_igv_type_id: item.sale_affectation_igv_type_id,
                sale_unit_price: item.sale_unit_price,
                series_enabled: item.series_enabled,
                stock: item.stock,
                unit_price: item.sale_unit_price,
                unit_type_id: item.unit_type_id,
                warehouses: item.warehouses
            };
            item.IdLoteSelected = null;
            if (item.affectation_igv_type_id === undefined) {
                item.affectation_igv_type_id = item.affectation_igv_type.id;
                // item.affectation_igv_type_id = "10";
            }
            item.discounts = [];
            item.charges = [];
            item.item_id = item.id;
            item.unit_price_value = item.sale_unit_price;
            item.input_unit_price_value = item.sale_unit_price;

            item.quantity = 1;

            let tempItem = itemsParsed.find(
                ip => ip.item_id == item.id || ip.id == item.id
            );
            if (tempItem !== undefined) {
                item.quantity = tempItem.quantity;
            }
            // item.quantity = itemsParsed.find(ip => ip.item_id == item.id).quantity;
            item.warehouse_id = null;

            return item;
        },
        update_stock() {
            this.$http
                .post(`/inventories/configuration`, this.form_control)
                .then(response => {
                    if (response.data.success) {
                        this.$toast.success(response.data.message);
                        this.restringir_stock = this.form_control.stock_control;
                    } else {
                        this.$toast.error(response.data.message);
                    }
                })
                .catch(error => {
                    if (error.response.status === 422) {
                        this.errors = error.response.data.errors;
                    } else {
                        console.log(error);
                    }
                })
                .then(() => {
                    this.loading_submit = false;
                });
        },
        async print_pdf(PrinterName, FileLink) {
            try {
                let config = qz.configs.create(PrinterName, {
                    scaleContent: false
                });
                if (!qz.websocket.isActive()) {
                    await qz.websocket.connect(config);
                }
                let data = [
                    {
                        type: "pdf",
                        format: "file",
                        data: FileLink
                    }
                ];
                qz.print(config, data).catch(e => {
                    this.$toast.error(e.message);
                });
                this.$toast.success(
                    "se esta imprimiendo el comprobante con exito"
                );
                // location.href = `/${this.resource}`;
            } catch (e) {
                this.$toast.error(e.message);
            }
        },
        async isUpdate() {
            if (this.id) {
                this.editDocument = true;
                await this.$http
                    .get(`/${this.resource}/record2/${this.id}`)
                    .then(response => {
                        this.form = {
                            boxes: response.data.data.boxes,
                            user_id: response.data.data.user_id,
                            id: response.data.data.id,
                            establishment_id:
                                response.data.data.establishment_id,
                            document_type_id:
                                response.data.data.document_type_id,
                            series_id: response.data.data.series_id,
                            number: response.data.data.number,
                            date_of_issue: response.data.data.date_of_issue,
                            time_of_issue: response.data.data.time_of_issue,
                            customer_id: response.data.data.customer_id,
                            currency_type_id:
                                response.data.data.currency_type_id,
                            purchase_order: response.data.data.purchase_order,
                            exchange_rate_sale:
                                response.data.data.exchange_rate_sale,
                            total_prepayment:
                                response.data.data.total_prepayment,
                            total_charge: response.data.data.total_charge,
                            total_discount: response.data.data.total_discount,
                            total_exportation:
                                response.data.data.total_exportation,
                            total_free: response.data.data.total_free,
                            total_taxed: response.data.data.total_taxed,
                            total_unaffected:
                                response.data.data.total_unaffected,
                            total_exonerated:
                                response.data.data.total_exonerated,
                            total_igv: response.data.data.total_igv,
                            total_base_isc: response.data.data.total_base_isc,
                            total_isc: response.data.data.total_isc,
                            total_base_other_taxes:
                                response.data.data.total_base_other_taxes,
                            total_other_taxes:
                                response.data.data.total_other_taxes,
                            total_plastic_bag_taxes:
                                response.data.data.total_plastic_bag_taxes,
                            total_taxes: response.data.data.total_taxes,
                            total_value: response.data.data.total_value,
                            total_rounded: response.data.data.total_rounded,
                            total_payment: response.data.data.total_payment,
                            total: response.data.data.total,
                            operation_type_id:
                                response.data.data.operation_type_id,
                            date_of_due: response.data.data.date_of_due,
                            afectar_caja: response.data.data.afectar_caja,
                            items: response.data.data.items,
                            charges: [],
                            discounts: [],
                            attributes: [],
                            guides: [],
                            payments: response.data.data.payments,
                            prepayments: [],
                            legends: [],
                            detraction: {},
                            additional_information:
                                response.data.data.additional_information[0],
                            plate_number: null,
                            has_prepayment: false,
                            affectation_type_prepayment: null,
                            actions: {
                                format_pdf: "a4"
                            },
                            hotel: {},
                            transport: {},
                            customer_address_id: null,
                            payment_condition_id:
                                response.data.data.payment_condition_id,
                            fee: []
                        };
                        if (this.form.payment_condition_id == "01") {
                            this.form.afectar_caja = true;
                        } else {
                            this.form.afectar_caja = false;
                        }

                        let item_save = this.form.items;
                        if (this.form.payments.length > 0) {
                            this.form.payments[0].payment_destination_id = this.payment_destinations[0].id;
                        }
                        this.generar_items(item_save);
                        this.filterSeries();
                        this.reloadDataCustomers(this.form.customer_id);
                        this.filterCustomers();
                        this.changeCustomer();
                        this.showClose = true;
                    });
                //     this.filterCustomers()
            }
        },
        generar_items(item) {
            for (let index = 0; index < item.length; index++) {
                this.form.items[index].additional_information = null;
                this.form.items[index].attributes = [];
                this.form.items[index].charges = [];
                this.form.items[index].discounts = [];
            }
        },
        teclasInit() {
            document.onkeydown = e => {
                const key = e.key;
                if (key == "F4") {
                    this.$nextTick(() => {
                        let input = this.$refs.cliente;
                        input.focus();
                        return false;
                    });
                }
                if (key == "F5") {
                    //Agregar cliente
                    this.showDialogNewPerson = true;
                    return false;
                }
                if (key == "F6") {
                    //Agregar Producto
                    this.clickAddItemInvoice();
                    return false;
                }
                if (key == "F7" && this.form.items.length > 0) {
                    //Guardar
                    this.submit();
                }
                if (key == "F8") {
                    //Cancelar
                    this.close();
                }
            };
        },

        changePaymentDestination(index) {
            // if(this.form.payments[index].payment_method_type_id=='01'){
            //     this.payment_destinations = this.cash
            // }else{
            //     this.payment_destinations = this.payment_destinations
            // }
            if (this.form.payments[0].payment_method_type_id != "01") {
                this.form.payments[0].payment = 0.0;
            } else {
                this.form.payments[0].payment = this.form.total;
            }
        },
        selectDocumentType() {
            this.form.document_type_id = this.select_first_document_type_03
                ? "03"
                : "01";
        },
        keyupCustomer() {
            if (this.input_person.number) {
                if (!isNaN(parseInt(this.input_person.number))) {
                    switch (this.input_person.number.length) {
                        case 8:
                            this.input_person.identity_document_type_id = "1";
                            this.showDialogNewPerson = true;
                            break;

                        case 11:
                            this.input_person.identity_document_type_id = "6";
                            this.showDialogNewPerson = true;
                            break;
                        default:
                            this.input_person.identity_document_type_id = "6";
                            this.showDialogNewPerson = true;
                            break;
                    }
                }
            }
        },
        addDocumentDetraction(detraction) {
            this.form.detraction = detraction;

            // this.has_data_detraction = (detraction.pay_constancy || detraction.detraction_type_id || detraction.payment_method_id || (detraction.amount && detraction.amount >0)) ? true:false
            this.has_data_detraction = detraction
                ? detraction.has_data_detraction
                : false;
        },
        clickAddItemInvoice: function() {
            this.recordItem = null;
            this.showDialogAddItem = true;
        },
        getFormatUnitPriceRow(unit_price) {
            return _.round(unit_price, 6);
            // return unit_price.toFixed(6)
        },
        discountGlobalPrepayment() {
            let global_discount = 0;
            this.form.prepayments.forEach(item => {
                global_discount += parseFloat(item.amount);
            });

            let base =
                this.form.affectation_type_prepayment == 10
                    ? parseFloat(this.form.total_taxed)
                    : parseFloat(this.form.total_exonerated);
            let amount = _.round(parseFloat(global_discount), 2);
            let factor = _.round(amount / base, 4);

            this.form.total_prepayment = _.round(global_discount, 2);

            if (this.form.affectation_type_prepayment == 10) {
                let discount = _.find(this.form.discounts, {
                    discount_type_id: "04"
                });

                if (global_discount > 0 && !discount) {
                    this.form.total_discount = _.round(amount, 2);
                    this.form.total_taxed = _.round(base - amount, 2);
                    this.form.total_value = _.round(base - amount, 2);
                    this.form.total_igv = _.round(
                        this.form.total_value * (this.percentage_igv / 100),
                        2
                    );
                    this.form.total_taxes = _.round(this.form.total_igv, 2);
                    this.form.total = _.round(
                        this.form.total_value + this.form.total_taxes,
                        2
                    );

