        calculateTotal() {
            let total_discount = 0;
            let total_charge = 0;
            let total_exportation = 0;
            let total_taxed = 0;
            let total_exonerated = 0;
            let total_unaffected = 0;
            let total_free = 0;
            let total_igv = 0;
            let total_value = 0;
            let total = 0;
            let total_plastic_bag_taxes = 0;
            this.form.items.forEach(row => {
                total_discount += parseFloat(row.total_discount);
                total_charge += parseFloat(row.total_charge);

                if (row.affectation_igv_type_id === "10") {
                    total_taxed += parseFloat(row.total_value);
                }
                if (row.affectation_igv_type_id === "20") {
                    total_exonerated += parseFloat(row.total_value);
                }
                if (row.affectation_igv_type_id === "30") {
                    total_unaffected += parseFloat(row.total_value);
                }
                if (row.affectation_igv_type_id === "40") {
                    total_exportation += parseFloat(row.total_value);
                }
                if (
                    ["10", "20", "30", "40"].indexOf(
                        row.affectation_igv_type_id
                    ) < 0
                ) {
                    total_free += parseFloat(row.total_value);
                }
                if (
                    ["10", "20", "30", "40"].indexOf(
                        row.affectation_igv_type_id
                    ) > -1
                ) {
                    total_igv += parseFloat(row.total_igv);

                    total += parseFloat(row.total);
                }
                total_value += parseFloat(row.total_value);
                total_plastic_bag_taxes += parseFloat(
                    row.total_plastic_bag_taxes
                );
            });

            this.form.total_exportation = _.round(total_exportation, 2);
            this.form.total_taxed = _.round(total_taxed, 2);
            this.form.total_exonerated = _.round(total_exonerated, 2);
            this.form.total_unaffected = _.round(total_unaffected, 2);
            this.form.total_free = _.round(total_free, 2);
            this.form.total_igv = _.round(total_igv, 2);
            this.form.total_value = _.round(total_value, 2);
            this.form.total_taxes = _.round(total_igv, 2);
            this.form.total_plastic_bag_taxes = _.round(
                total_plastic_bag_taxes,
                2
            );
            // this.form.total = _.round(total, 2)
            this.form.total = _.round(
                total + this.form.total_plastic_bag_taxes,
                2
            );

            if (this.enabled_discount_global) this.discountGlobal();

            if (this.prepayment_deduction) this.discountGlobalPrepayment();

            if (this.form.operation_type_id === "1001")
                this.changeDetractionType();

            this.setTotalDefaultPayment();
            this.form.total_rounded = Math.abs(
                Math.round(parseFloat(this.form.total) * 10) / 10 -
                    this.form.total
            ).toFixed(2);
            this.form.total_payment =
                Math.round(parseFloat(this.form.total) * 10) / 10;
        },
        setTotalDefaultPayment() {
            if (this.form.payments && this.form.payments.length > 0) {
                this.form.payments[0].payment = this.form.total;
            }
        },
        changeTypeDiscount() {
            this.calculateTotal();
        },
        discountGlobal() {
            let base = this.form.total_taxed;

            let amount = this.is_amount
                ? parseFloat(this.total_global_discount)
                : (parseFloat(this.total_global_discount) / 100) * base;
            let factor = this.is_amount
                ? _.round(amount / base, 5)
                : _.round(parseFloat(this.total_global_discount) / 100, 5);

            if (
                this.total_global_discount > 0 &&
                this.form.discounts.length == 0
            ) {
                this.form.discounts.push({
                    discount_type_id: "02",
                    description: "Descuento Global afecta a la base imponible",
                    factor: 0,
                    amount: 0,
                    base: 0
                });
            }

            if (this.form.discounts.length) {
                this.form.total_discount = _.round(amount, 2);
                this.form.total_value = _.round(base - amount, 2);
                this.form.total_igv = _.round(
                    this.form.total_value * (this.percentage_igv / 100),
                    2
                );
                this.form.total_taxes = _.round(this.form.total_igv, 2);
                this.form.total = _.round(
                    this.form.total_value + this.form.total_taxes,
                    2
                );

                this.form.total_taxed = this.form.total_value;

                this.form.discounts[0].base = base;
                this.form.discounts[0].amount = _.round(amount, 2);
                this.form.discounts[0].factor = factor;
            }
        },
