            let not_equal_affectation_type = 0;

            await this.form.items.forEach(item => {
                if (
                    item.affectation_igv_type_id !=
                    this.form.affectation_type_prepayment
                ) {
                    not_equal_affectation_type++;
                }
            });

            return {
                success: not_equal_affectation_type > 0 ? false : true,
                message:
                    "Los items deben tener tipo de afectación igual al seleccionado en el anticipo"
            };
        },

        async submit() {
            if (this.form.has_prepayment || this.prepayment_deduction) {
                let error_prepayment = await this.validateAffectationTypePrepayment();
                if (!error_prepayment.success) {
                    return this.$toast.error(error_prepayment.message);
                    this.validarForm = true;
                } else {
                    this.validarForm = false;
                }
            }
            if(this.payment_condition_id == '01'){
                let sum = this.boxes.reduce((a, b) => a + (b['amount'] || 0), 0);
                if(sum == 0){
                    return this.$toast.error('El monto de pago debe ser mayor a 0');
                }
            }
            if (this.is_receivable) {
                this.form.payments = [];
            } else {
                let validate = await this.validate_payments();
                if (
                    validate.acum_total > parseFloat(this.form.total) ||
                    validate.error_by_item > 0
                ) {
                    this.validarForm = true;
                    return this.$toast.error(
                        "Los montos ingresados superan al monto a pagar o son incorrectos"
                    );
                } else {
                    this.validarForm = false;
                }
            }

            await this.deleteInitGuides();
            await this.asignPlateNumberToItems();

            let val_detraction = await this.validateDetraction();
            if (!val_detraction.success) {
                this.validarForm = true;
                return this.$toast.error(val_detraction.message);
            } else {
                this.validarForm = false;
            }

            if (this.validarForm == false) {
                let form_efectivo = {
                    enter_amount: 0,
                    difference: 0
                };
                const response_efectivo = this.$http.post(
                    `/efectivo`,
                    form_efectivo
                );
                if (this.form.payment_condition_id === "03")
                    this.form.payment_condition_id = "02";
                this.loading_submit = true;
                this.$http
                    .post(`/${this.resource}`, this.form)
                    .then(response => {
                        if (response.data.success) {
                            this.user_default = this.form.user_id;
                            this.$eventHub.$emit("reloadDataItems", null);
                            this.resetForm();
                            this.clickAddBoxes(true);
                            if (this.show_restriction == 1) {
                                if (this.form_control.stock_control == false) {
                                    this.form_control.stock_control = true;
                                    this.update_stock();
                                }
                            }
                            this.documentNewId = response.data.data.id;

                            if (this.configuration.print_direct == 1) {
                                let formatoPdf = "";
                                if (response.data.data.format_printer == "1") {
                                    formatoPdf = response.data.data.print_a4;
                                } else if (
                                    response.data.data.format_printer == "2"
                                ) {
                                    formatoPdf = response.data.data.print_a5;
                                } else if (
                                    response.data.data.format_printer == "3"
                                ) {
                                    formatoPdf =
                                        response.data.data.print_ticket;
                                } else if (
                                    response.data.data.format_printer == "4"
                                ) {
                                    formatoPdf =
                                        response.data.data.print_ticket;
                                }

                                this.$confirm(
                                    "¿Desea Imprimir el Comprobante de Pago ?",
                                    "Comprobante de Pago",
                                    {
                                        distinguishCancelAndClose: true,
                                        confirmButtonText: "Aceptar",
                                        cancelButtonText: "Cancelar"
                                    }
                                )
                                    .then(() => {
                                        this.print_pdf(
                                            response.data.data.printer,
                                            formatoPdf
                                        );

                                        //location.href = (this.isContingency) ? `/contingencies` : `/${this.resource}`
                                    })
                                    .catch(action => {
                                        if (
                                            this.typeUser == "admin" ||
                                            this.typeUser == "superadmin"
                                        ) {
                                            location.href = this.isContingency
                                                ? `/contingencies`
                                                : `/${this.resource}`;
                                        } else {
                                            location.href = this.isContingency
                                                ? `/contingencies`
                                                : `/caja/documents`;
                                        }
                                    });
                            } else {
                                this.showDialogOptions = true;
                            }
                            this.isUpdate();
                        } else {
                            this.$toast.error(response.data.message);
                        }
                    })
                    .catch(error => {
                        //alert('sdsd')
                        if (error.response.status === 422) {
                            this.errors = error.response.data;
                        } else {
                            this.$toast.error(error.response.data.message);
                        }
                    })
                    .then(() => {
                        this.changePaymentCondition();
                        this.loading_submit = false;
                    });
            }
        },
        validate_payments() {
            //eliminando items de pagos
            for (let index = 0; index < this.form.payments.length; index++) {
                if (parseFloat(this.form.payments[index].payment) === 0)
                    this.form.payments.splice(index, 1);
            }

            let error_by_item = 0;
            let acum_total = 0;

            this.form.payments.forEach(item => {
                acum_total += parseFloat(item.payment);
                if (item.payment <= 0 || item.payment == null) error_by_item++;
            });

            return {
                error_by_item: error_by_item,
                acum_total: acum_total
            };
        },

        close() {
            this.$confirm("Desea Cancelar?", "Warning", {
                confirmButtonText: "Aceptar",
                cancelButtonText: "Cancelar",
                type: "warning"
            }).then(() => {
                location.href = this.is_contingency
                    ? `/contingencies`
                    : `/${this.resource}`;
            });
        },
        reloadDataCustomers(customer_id) {
            // this.$http.get(`/${this.resource}/table/customers`).then((response) => {
            //     this.customers = response.data
            //     this.form.customer_id = customer_id
            // })
            this.$http
                .get(`/${this.resource}/search/customer/${customer_id}`)
                .then(response => {
                    this.customers = response.data.customers;
                    this.form.customer_id = customer_id;
                });
        },
        changeCustomer() {
            this.customer_addresses = [];
            let customer = _.find(this.customers, {
                id: this.form.customer_id
            });
            if (customer) {
                this.customer_addresses = customer.addresses;
                if (customer.address) {
                    this.customer_addresses.unshift({
                        id: null,
                        address: customer.address
                    });
                }
            }

            /*if(this.customer_addresses.length > 0) {
                let address = _.find(this.customer_addresses, {'main' : 1});
                this.form.customer_address_id = address.id;
            }*/
        },
        calculateItem(index, quantity, unit_price) {
            this.form.items[index].quantity = quantity;
            let total_venta = _.round(
                Math.round(parseFloat(quantity) * parseFloat(unit_price) * 10) /
                    10,
                2
            );
            this.form.items[index].total = total_venta;
            if (this.form.items[index].affectation_igv_type_id == "10") {
                this.form.items[index].total_value = (
                    this.form.items[index].total /
                    (1 + this.percentage_igv / 100)
                ).toFixed(2);
                this.form.items[index].total_taxes = (
                    (quantity * unit_price * (this.percentage_igv / 100)) /
                    (1 + this.percentage_igv / 100)
                ).toFixed(2);
                this.form.items[index].total_base_igv = _.round(
                    this.form.items[index].total /
                        (1 + this.percentage_igv / 100),
                    2
                );
                this.form.items[index].unit_value = (
                    unit_price /
                    (1 + this.percentage_igv / 100)
                ).toFixed(6);
                this.form.items[index].total_igv = _.round(
                    (this.form.items[index].total /
                        (1 + this.percentage_igv / 100)) *
                        (this.percentage_igv / 100),
                    2
                );
                this.form.items[index].total_base_igv = _.round(
                    this.form.items[index].total /
                        (1 + this.percentage_igv / 100),
                    2
                );
            } else {
                this.form.items[index].total_value =
                    Math.round(
                        parseFloat(quantity) * parseFloat(unit_price) * 10
                    ) / 10;
                this.form.items[index].total_taxes = 0.0;
                this.form.items[index].total_base_igv = _.round(
                    Math.round(
                        parseFloat(quantity) * parseFloat(unit_price) * 10
                    ) / 10,
                    2
                );
                this.form.items[index].unit_value = unit_price;
                this.form.items[index].total_igv = 0;
                this.form.items[index].total_base_igv = _.round(
                    Math.round(
                        parseFloat(quantity) * parseFloat(unit_price) * 10
                    ) / 10,
                    2
                );
            }

            this.calculateTotal();
        },
        clickAddFeeNew() {
            let first = {
                id: "05",
                number_days: 0
            };
            if (this.credit_payment_metod[0] !== undefined) {
                first = this.credit_payment_metod[0];
            }

            // let date = moment()
            //     .add(first.number_days, 'days')
            //     .format('YYYY-MM-DD')

            let date = moment(this.form.date_of_issue)
                .add(first.number_days, "days")
                .format("YYYY-MM-DD");

            this.form.date_of_due = date;
            this.form.fee.push({
                id: null,
                document_id: null,
                payment_method_type_id: first.id,
                // reference: null,
                // payment_destination_id: this.getPaymentDestinationId(),
                // payment: 0,

                date: date,
                currency_type_id: this.form.currency_type_id,
                amount: 0
            });
            this.calculateFee();
        },
        initDataPaymentCondition01() {
            this.readonly_date_of_due = false;
            this.enabled_payments = true;
            this.form.date_of_due = this.form.date_of_issue;
            this.form.payment_method_type_id = null;
        },
        changePaymentCondition() {
            // this.form.fee = [];
            // this.form.payments = [];
            // if (this.form.payment_condition_id === "01") {
            //     // this.clickAddPayment();
            //     this.clickAddBoxes();
            // }
            // if (this.form.payment_condition_id === "02") {
            //     this.clickAddFee();
            // }
            ///
            this.form.fee = [];
            this.form.payments = [];
            if (this.form.payment_condition_id === "01") {
                this.clickAddBoxes();
                this.initDataPaymentCondition01();
            }
            if (this.form.payment_condition_id === "02") {
                this.clickAddFeeNew();
                this.readonly_date_of_due = true;
            }
            if (this.form.payment_condition_id === "03") {
                this.clickAddFee();
            }

            // if(this.isCreditPaymentCondition){
            // this.changeRetention()
            // }

            if (!_.isEmpty(this.form.retention)) {
                this.setTotalPendingAmountRetention(this.form.retention.amount);
            }
        },
        clickAddFee() {
            this.form.fee.push({
                id: null,
                date: moment(this.form.date_of_issue)
                    .add(this.form.fee.length + 1, "days")
                    .format("YYYY-MM-DD"),
                currency_type_id: this.form.currency_type_id,
                amount: 0
            });
            this.calculateFee();
        },
        clickRemoveFee(index) {
            this.form.fee.splice(index, 1);
            this.calculateFee();
        },
        calculateFee() {
            let fee_count = this.form.fee.length;
            let total = this.form.total;
            let accumulated = 0;
            let amount = _.round(total / fee_count, 2);
            _.forEach(this.form.fee, row => {
                accumulated += amount;
                if (total - accumulated < 0) {
                    amount = _.round(total - accumulated + amount, 2);
                }
                row.amount = amount;
            });
        }
    },
    mounted() {
        // this.teclasInit();
        if (this.id != null) {
            this.editandoDocument = true;
        }
        this.loader = true;
    }
};
</script>



